```typescript
export type CreativeState =
  | { status: "empty" }
  | { status: "uploaded"; id: string; assetUrl: string }
  | { status: "reviewed"; id: string; assetUrl: string; reviewer: string }
  | { status: "published"; id: string; assetUrl: string; publishedAt: string }
  | { status: "archived"; id: string };

export type CreativeCommand =
  | { type: "upload"; id: string; assetUrl: string }
  | { type: "review"; reviewer: string }
  | { type: "publish"; at: string }
  | { type: "archive" };

export type CreativeEvent =
  | { type: "CreativeUploaded"; id: string; assetUrl: string }
  | { type: "CreativeReviewed"; reviewer: string }
  | { type: "CreativePublished"; at: string }
  | { type: "CreativeArchived" };

export class CreativeError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "CreativeError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const creativeDecider: Decider<CreativeCommand, CreativeEvent, CreativeState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "upload":
        if (state.status !== "empty") throw new CreativeError("ALREADY_UPLOADED");
        return [{ type: "CreativeUploaded", id: command.id, assetUrl: command.assetUrl }];
      case "review":
        if (state.status !== "uploaded") throw new CreativeError("NOT_UPLOADED");
        return [{ type: "CreativeReviewed", reviewer: command.reviewer }];
      case "publish":
        if (state.status !== "reviewed") throw new CreativeError("NOT_REVIEWED");
        return [{ type: "CreativePublished", at: command.at }];
      case "archive":
        if (state.status === "archived" || state.status === "empty") throw new CreativeError("CANNOT_ARCHIVE");
        return [{ type: "CreativeArchived" }];
      default: {
        const _never: never = command;
        throw new CreativeError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CreativeUploaded":
        return { status: "uploaded", id: event.id, assetUrl: event.assetUrl };
      case "CreativeReviewed":
        if (state.status !== "uploaded") return state;
        return { status: "reviewed", id: state.id, assetUrl: state.assetUrl, reviewer: event.reviewer };
      case "CreativePublished":
        if (state.status !== "reviewed") return state;
        return { status: "published", id: state.id, assetUrl: state.assetUrl, publishedAt: event.at };
      case "CreativeArchived":
        if (state.status === "empty") return state;
        return { status: "archived", id: "id" in state ? state.id : "" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

A Decider pairs three pure pieces: an `initialState` literal, a `decide(command, state)` that validates invariants and returns the resulting events, and an `evolve(state, event)` that folds events into new state. No I/O, no clocks, no randomness — every aggregate is a deterministic replay.

```typescript
export type AuctionRoomState =
  | { status: "closed" }
  | { status: "open"; id: string; highBid: number; highBidder: string | null };

export type AuctionRoomCommand =
  | { type: "open"; id: string; reservePrice: number }
  | { type: "bid"; bidder: string; amount: number }
  | { type: "close" };

export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; id: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number }
  | { type: "AuctionRoomClosed" };

export class AuctionRoomError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "AuctionRoomError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const auctionRoomDecider: Decider<AuctionRoomCommand, AuctionRoomEvent, AuctionRoomState> = {
  initialState: { status: "closed" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status === "open") throw new AuctionRoomError("ALREADY_OPEN");
        return [{ type: "AuctionRoomOpened", id: command.id, reservePrice: command.reservePrice }];
      case "bid":
        if (state.status !== "open") throw new AuctionRoomError("NOT_OPEN");
        if (command.amount <= state.highBid) throw new AuctionRoomError("BID_TOO_LOW");
        return [{ type: "BidPlaced", bidder: command.bidder, amount: command.amount }];
      case "close":
        if (state.status !== "open") throw new AuctionRoomError("NOT_OPEN");
        return [{ type: "AuctionRoomClosed" }];
      default: {
        const _never: never = command;
        throw new AuctionRoomError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AuctionRoomOpened":
        return { status: "open", id: event.id, highBid: event.reservePrice, highBidder: null };
      case "BidPlaced":
        if (state.status !== "open") return state;
        return { status: "open", id: state.id, highBid: event.amount, highBidder: event.bidder };
      case "AuctionRoomClosed":
        return { status: "closed" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
