```typescript
export type BidderState =
  | { status: "new" }
  | { status: "active"; id: string; balanceCents: number }
  | { status: "suspended"; id: string; balanceCents: number; reason: string };

export type BidderCommand =
  | { type: "register"; id: string; openingBalanceCents: number }
  | { type: "placeBid"; amountCents: number }
  | { type: "suspend"; reason: string }
  | { type: "reinstate" };

export type BidderEvent =
  | { type: "BidderRegistered"; id: string; openingBalanceCents: number }
  | { type: "BidderBidPlaced"; amountCents: number }
  | { type: "BidderSuspended"; reason: string }
  | { type: "BidderReinstated" };

export class BidderError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "BidderError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const bidderDecider: Decider<BidderCommand, BidderEvent, BidderState> = {
  initialState: { status: "new" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "new") throw new BidderError("ALREADY_REGISTERED");
        if (command.openingBalanceCents < 0) throw new BidderError("NEGATIVE_BALANCE");
        return [{ type: "BidderRegistered", id: command.id, openingBalanceCents: command.openingBalanceCents }];
      case "placeBid":
        if (state.status === "new") throw new BidderError("NOT_REGISTERED");
        if (state.status === "suspended") throw new BidderError("SUSPENDED");
        if (command.amountCents > state.balanceCents) throw new BidderError("INSUFFICIENT_FUNDS");
        return [{ type: "BidderBidPlaced", amountCents: command.amountCents }];
      case "suspend":
        if (state.status !== "active") throw new BidderError("NOT_ACTIVE");
        return [{ type: "BidderSuspended", reason: command.reason }];
      case "reinstate":
        if (state.status !== "suspended") throw new BidderError("NOT_SUSPENDED");
        return [{ type: "BidderReinstated" }];
      default: {
        const _never: never = command;
        throw new BidderError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "BidderRegistered":
        return { status: "active", id: event.id, balanceCents: event.openingBalanceCents };
      case "BidderBidPlaced":
        if (state.status !== "active") return state;
        return { status: "active", id: state.id, balanceCents: state.balanceCents - event.amountCents };
      case "BidderSuspended":
        if (state.status !== "active") return state;
        return { status: "suspended", id: state.id, balanceCents: state.balanceCents, reason: event.reason };
      case "BidderReinstated":
        if (state.status !== "suspended") return state;
        return { status: "active", id: state.id, balanceCents: state.balanceCents };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
