```typescript
export type MediaBuyState =
  | { status: "none" }
  | { status: "approved"; id: string; budgetCents: number; spentCents: number }
  | { status: "closed"; id: string; totalSpentCents: number };

export type MediaBuyCommand =
  | { type: "approveBudget"; id: string; budgetCents: number }
  | { type: "commitSpend"; amountCents: number }
  | { type: "close" };

export type MediaBuyEvent =
  | { type: "MediaBuyBudgetApproved"; id: string; budgetCents: number }
  | { type: "MediaBuySpendCommitted"; amountCents: number }
  | { type: "MediaBuyClosed"; totalSpentCents: number };

export class MediaBuyError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "MediaBuyError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const mediaBuyDecider: Decider<MediaBuyCommand, MediaBuyEvent, MediaBuyState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "approveBudget":
        if (state.status !== "none") throw new MediaBuyError("ALREADY_APPROVED");
        if (command.budgetCents <= 0) throw new MediaBuyError("BUDGET_INVALID");
        return [{ type: "MediaBuyBudgetApproved", id: command.id, budgetCents: command.budgetCents }];
      case "commitSpend":
        if (state.status !== "approved") throw new MediaBuyError("NOT_APPROVED");
        if (command.amountCents <= 0) throw new MediaBuyError("AMOUNT_INVALID");
        if (state.spentCents + command.amountCents > state.budgetCents) throw new MediaBuyError("OVER_BUDGET");
        return [{ type: "MediaBuySpendCommitted", amountCents: command.amountCents }];
      case "close":
        if (state.status !== "approved") throw new MediaBuyError("NOT_OPEN");
        return [{ type: "MediaBuyClosed", totalSpentCents: state.spentCents }];
      default: {
        const _never: never = command;
        throw new MediaBuyError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "MediaBuyBudgetApproved":
        return { status: "approved", id: event.id, budgetCents: event.budgetCents, spentCents: 0 };
      case "MediaBuySpendCommitted":
        if (state.status !== "approved") return state;
        return { status: "approved", id: state.id, budgetCents: state.budgetCents, spentCents: state.spentCents + event.amountCents };
      case "MediaBuyClosed":
        if (state.status !== "approved") return state;
        return { status: "closed", id: state.id, totalSpentCents: event.totalSpentCents };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
