```typescript
export type ImpressionEvent =
  | { type: "ImpressionRecorded"; adId: string; at: string }
  | { type: "ImpressionInvalidated"; adId: string; reason: string }
  | { type: "ImpressionBilled"; adId: string; costCents: number };

export interface ImpressionCountView {
  readonly perAd: Readonly<Record<string, number>>;
  readonly totalBilledCents: number;
}

export const emptyView: ImpressionCountView = { perAd: {}, totalBilledCents: 0 };

export function project(view: ImpressionCountView, event: ImpressionEvent): ImpressionCountView {
  switch (event.type) {
    case "ImpressionRecorded": {
      const current = view.perAd[event.adId] ?? 0;
      return { ...view, perAd: { ...view.perAd, [event.adId]: current + 1 } };
    }
    case "ImpressionInvalidated": {
      const current = view.perAd[event.adId] ?? 0;
      const next = Math.max(0, current - 1);
      return { ...view, perAd: { ...view.perAd, [event.adId]: next } };
    }
    case "ImpressionBilled":
      return { ...view, totalBilledCents: view.totalBilledCents + event.costCents };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function buildImpressionView(events: ImpressionEvent[]): ImpressionCountView {
  return events.reduce(project, emptyView);
}
```

```typescript
export type AdAnalyticsEvent =
  | { type: "ImpressionRecorded"; creativeId: string }
  | { type: "ClickRecorded"; creativeId: string; referrer: string }
  | { type: "ClickReverted"; creativeId: string };

export interface CreativeCtrRow {
  readonly impressions: number;
  readonly clicks: number;
}

export interface CreativeCtrView {
  readonly rows: Readonly<Record<string, CreativeCtrRow>>;
}

export const emptyView: CreativeCtrView = { rows: {} };

function bump(view: CreativeCtrView, id: string, d: { impressions?: number; clicks?: number }): CreativeCtrView {
  const prev = view.rows[id] ?? { impressions: 0, clicks: 0 };
  const next: CreativeCtrRow = {
    impressions: prev.impressions + (d.impressions ?? 0),
    clicks: Math.max(0, prev.clicks + (d.clicks ?? 0)),
  };
  return { rows: { ...view.rows, [id]: next } };
}

export function project(view: CreativeCtrView, event: AdAnalyticsEvent): CreativeCtrView {
  switch (event.type) {
    case "ImpressionRecorded":
      return bump(view, event.creativeId, { impressions: 1 });
    case "ClickRecorded":
      return bump(view, event.creativeId, { clicks: 1 });
    case "ClickReverted":
      return bump(view, event.creativeId, { clicks: -1 });
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function ctr(row: CreativeCtrRow): number {
  return row.impressions === 0 ? 0 : row.clicks / row.impressions;
}
```

A read-model projection is a pure fold over the subset of events it cares about. It does not rebuild aggregate state — it denormalises just enough for the query side.

```typescript
export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string; reservePrice: number }
  | { type: "BidPlaced"; roomId: string; bidder: string; amount: number }
  | { type: "AuctionRoomClosed"; roomId: string };

export interface LeaderboardRow {
  readonly roomId: string;
  readonly highBid: number;
  readonly leader: string | null;
  readonly closed: boolean;
}

export interface LeaderboardView {
  readonly rooms: Readonly<Record<string, LeaderboardRow>>;
}

export const emptyView: LeaderboardView = { rooms: {} };

export function project(view: LeaderboardView, event: AuctionRoomEvent): LeaderboardView {
  switch (event.type) {
    case "AuctionRoomOpened": {
      const row: LeaderboardRow = { roomId: event.roomId, highBid: event.reservePrice, leader: null, closed: false };
      return { rooms: { ...view.rooms, [event.roomId]: row } };
    }
    case "BidPlaced": {
      const prev = view.rooms[event.roomId];
      if (!prev || prev.closed || event.amount <= prev.highBid) return view;
      const row: LeaderboardRow = { ...prev, highBid: event.amount, leader: event.bidder };
      return { rooms: { ...view.rooms, [event.roomId]: row } };
    }
    case "AuctionRoomClosed": {
      const prev = view.rooms[event.roomId];
      if (!prev) return view;
      return { rooms: { ...view.rooms, [event.roomId]: { ...prev, closed: true } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
