```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

interface AdvertisementV1 {
  readonly id: string;
  readonly headline: string;
}

interface AdvertisementV2 {
  readonly id: string;
  readonly headline: string;
  readonly priority: number;
}

interface AdvertisementV3 {
  readonly id: string;
  readonly title: string;
  readonly subtitle: string;
  readonly priority: number;
}

export type CurrentAdvertisement = AdvertisementV3;
export const CURRENT_VERSION = 3 as const;

function v1Tov2(prev: AdvertisementV1): AdvertisementV2 {
  return { ...prev, priority: 5 };
}

function v2Tov3(prev: AdvertisementV2): AdvertisementV3 {
  const [title, ...rest] = prev.headline.split(" - ");
  return { id: prev.id, priority: prev.priority, title, subtitle: rest.join(" - ") };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentAdvertisement> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as AdvertisementV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as AdvertisementV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported snapshot version: ${snap.version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentAdvertisement };
