  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
    public readonly actual: bigint | "no_stream",
  ) {
    super(`Concurrency conflict on ${stream}: expected ${String(expected)}, got ${String(actual)}`);
    this.name = "ConcurrencyConflict";
  }
}

function isConflict(err: unknown): err is { code: "WRONG_EXPECTED_REVISION"; actualRevision: bigint | "no_stream" } {
  return typeof err === "object" && err !== null && (err as { code?: unknown }).code === "WRONG_EXPECTED_REVISION";
