export type ImpressionEvent =
  | { type: "ImpressionRecorded"; adId: string; at: string }
  | { type: "ImpressionInvalidated"; adId: string; reason: string };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface ReadModelStore {
  apply(event: ImpressionEvent): Promise<void>;
}

export interface EventStore {
  readFrom(position: bigint): AsyncIterable<{ position: bigint; event: ImpressionEvent }>;
}

export interface SubscriptionDeps {
  readonly name: string;
  readonly checkpoints: CheckpointStore;
  readonly feed: EventStore;
  readonly readModel: ReadModelStore;
}

export async function runSubscription(deps: SubscriptionDeps): Promise<void> {
  const start = (await deps.checkpoints.read(deps.name)) ?? 0n;
  let position = start;
  const iterator = deps.feed.readFrom(start);
  try {
    for await (const envelope of iterator) {
      await deps.readModel.apply(envelope.event);
      position = envelope.position;
      await deps.checkpoints.write(deps.name, position);
    }
  } catch (err) {
    console.error(`[${deps.name}] subscription halted at ${position}`, err);
    throw err;
  }
}
```

Writing the checkpoint before the projection risks skipping an event if the process crashes between writing the checkpoint and applying the event. Writing after is at-least-once: on crash, the subscription re-applies the last event — so the read model must either be idempotent or tolerant of duplicates.

