export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number }
  | { type: "AuctionRoomClosed" };

export interface AuctionRoomState {
  readonly roomId: string;
  readonly highBid: number;
  readonly leader: string | null;
  readonly closed: boolean;
}

export const initialRoom: AuctionRoomState = { roomId: "", highBid: 0, leader: null, closed: false };

export function evolve(state: AuctionRoomState, event: AuctionRoomEvent): AuctionRoomState {
  switch (event.type) {
    case "AuctionRoomOpened":
      return { roomId: event.roomId, highBid: event.reservePrice, leader: null, closed: false };
    case "BidPlaced":
      if (state.closed || event.amount <= state.highBid) return state;
      return { ...state, highBid: event.amount, leader: event.bidder };
    case "AuctionRoomClosed":
      return { ...state, closed: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

export async function loadRoom(stream: AsyncIterable<AuctionRoomEvent>): Promise<AuctionRoomState> {
  return aggregateStream(stream, evolve, initialRoom);
}
