export type SagaInput =
  | { type: "CampaignFlightLaunched"; flightId: string }
  | { type: "InventoryReserved"; flightId: string; reservationId: string }
  | { type: "BillingStarted"; flightId: string };

export type SagaCommand =
  | { type: "ReserveInventory"; flightId: string }
  | { type: "StartBilling"; flightId: string; reservationId: string };

export type SagaStatus = "idle" | "reservingInventory" | "billing" | "done";

export interface SagaState {
  readonly status: SagaStatus;
  readonly flightId: string | null;
  readonly reservationId: string | null;
}

export const initialSaga: SagaState = { status: "idle", flightId: null, reservationId: null };

export interface SagaStep {
  readonly nextState: SagaState;
  readonly command: SagaCommand | null;
}

export function react(state: SagaState, event: SagaInput): SagaStep {
  switch (event.type) {
    case "CampaignFlightLaunched":
      if (state.status !== "idle") return { nextState: state, command: null };
      return {
        nextState: { status: "reservingInventory", flightId: event.flightId, reservationId: null },
        command: { type: "ReserveInventory", flightId: event.flightId },
      };
    case "InventoryReserved":
      if (state.status !== "reservingInventory" || state.flightId !== event.flightId) {
        return { nextState: state, command: null };
      }
      return {
        nextState: { status: "billing", flightId: state.flightId, reservationId: event.reservationId },
        command: { type: "StartBilling", flightId: state.flightId, reservationId: event.reservationId },
      };
    case "BillingStarted":
      if (state.status !== "billing") return { nextState: state, command: null };
      return {
        nextState: { ...state, status: "done" },
        command: null,
      };
    default: {
      const _never: never = event;
      return { nextState: state, command: null };
    }
  }
}

export interface CommandBus {
  send(cmd: SagaCommand): Promise<void>;
}

export interface EventStore {
  subscribe(name: string): AsyncIterable<SagaInput>;
}

export async function runSaga(store: EventStore, bus: CommandBus, name: string): Promise<void> {
  let state = initialSaga;
  for await (const event of store.subscribe(name)) {
    const step = react(state, event);
    state = step.nextState;
    if (step.command) await bus.send(step.command);
  }
}
