}

export async function appendWithOutbox(
  stream: string,
  events: readonly AdSlotEvent[],
  outboxRows: readonly OutboxRow[],
  expectedRevision: ExpectedRevision,
  conn: TransactionalConnection,
): Promise<void> {
  const tx = await conn.begin();
  try {
    await tx.appendToStream(stream, events, { expectedRevision });
    if (outboxRows.length > 0) await tx.insertOutbox(outboxRows);
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
  // NOTE: a separate worker polls unpublished outbox rows, publishes the
  // payload, and marks `publishedAt`. That worker is not implemented here.
}
```

```typescript
export type ClickEvent =
  | { type: "ClickRecorded"; clickId: string; creativeId: string; at: string }
  | { type: "ClickReverted"; clickId: string };

export interface StoredEvent<E> {
  readonly revision: bigint;
  readonly event: E;
}

export interface EventStore<E> {
  readBatch(stream: string, from: bigint, limit: number): Promise<readonly StoredEvent<E>[]>;
}

export async function* readFromStream(
  store: EventStore<ClickEvent>,
  stream: string,
  fromRevision: bigint,
  batchSize = 128,
): AsyncIterable<StoredEvent<ClickEvent>> {
  let cursor = fromRevision;
  for (;;) {
    const batch = await store.readBatch(stream, cursor, batchSize);
    if (batch.length === 0) return;
    for (const stored of batch) {
      yield stored;
      cursor = stored.revision + 1n;
    }
    if (batch.length < batchSize) return;
  }
}

export async function main(store: EventStore<ClickEvent>): Promise<void> {
  for await (const stored of readFromStream(store, "clicks-abc", 0n)) {
    if (stored.event.type === "ClickRecorded") {
      console.log(stored.event.creativeId, stored.event.at);
    }
  }
}

main(null as unknown as EventStore<ClickEvent>).catch((err: unknown) => {
  console.error(err);
  process.exitCode = 1;
});
