```typescript
import { Effect } from "effect";

export type AdvertisementEvent =
  | { type: "AdvertisementSubmitted"; id: string; headline: string }
  | { type: "AdvertisementApproved"; at: string }
  | { type: "AdvertisementRetired" };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  appendToStream(
    stream: string,
    events: readonly AdvertisementEvent[],
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict {
  readonly _tag = "ConcurrencyConflict" as const;
  constructor(public readonly stream: string) {}
}

export class AppendFailed {
  readonly _tag = "AppendFailed" as const;
  constructor(public readonly cause: unknown) {}
}

export function appendAdvertisement(
  store: EventStore,
  stream: string,
  events: readonly AdvertisementEvent[],
  expectedRevision: ExpectedRevision,
) {
  return Effect.tryPromise({
    try: () => store.appendToStream(stream, events, { expectedRevision }),
    catch: (err): ConcurrencyConflict | AppendFailed => {
      if ((err as { code?: string }).code === "WRONG_EXPECTED_REVISION") {
        return new ConcurrencyConflict(stream);
      }
      return new AppendFailed(err);
    },
  });
}
```

Wrap the iteration so errors surface, track the cursor explicitly, and propagate failures out of the top-level async call.

```typescript
export type AuctionRoomEvent =
  | { type: "AuctionRoomOpened"; roomId: string; reservePrice: number }
  | { type: "BidPlaced"; bidder: string; amount: number }
  | { type: "AuctionRoomClosed" };

export interface StoredEvent {
  readonly revision: bigint;
  readonly event: AuctionRoomEvent;
}

export interface EventStore {
  read(stream: string, from: bigint): AsyncIterable<StoredEvent>;
}

export async function drain(
  store: EventStore,
  stream: string,
  from: bigint,
  apply: (event: AuctionRoomEvent) => Promise<void>,
): Promise<bigint> {
  let cursor = from;
  try {
    for await (const stored of store.read(stream, from)) {
      await apply(stored.event);
      cursor = stored.revision;
    }
    return cursor;
  } catch (err) {
    console.error(`drain of ${stream} failed at revision ${cursor}`, err);
    throw err;
  }
}

async function main(): Promise<void> {
  const store: EventStore = null as unknown as EventStore;
  await drain(store, "room-42", 0n, async () => {
    // project into read model
  });
}

main().catch((err: unknown) => {
  console.error(err);
  process.exitCode = 1;
});
